llm_verdict.message:
{
  "applied": true,
  "message": "Remediation applied: kernel.kexec_load_disabled set to 1 both runtime and persistent. No impact on core services; potential limited to kdump/kexec-based reboot which are not essential for system availability.",
  "commands": [
    {
      "step": "check_current",
      "command": "sysctl kernel.kexec_load_disabled"
    },
    {
      "step": "set_runtime",
      "command": "sysctl -w kernel.kexec_load_disabled=1"
    },
    {
      "step": "ensure_persistent",
      "description": "Search /etc/sysctl.d/*.conf for existing kernel.kexec_load_disabled lines, set to 1 if found; otherwise add new file.",
      "subcommands": [
        {
          "action": "read_file",
          "path": "/etc/sysctl.d/",
          "pattern": "*.conf",
          "exclude_symlink_to": "/etc/sysctl.conf"
        },
        {
          "action": "run_cmd",
          "command": "grep -l 'kernel.kexec_load_disabled' {file}"
        },
        {
          "action": "run_cmd",
          "command": "sed -i 's/^\\s*#*\\s*kernel.kexec_load_disabled\\s*.*/kernel.kexec_load_disabled = 1/' {file}"
        },
        {
          "action": "run_cmd",
          "command": "echo 'kernel.kexec_load_disabled = 1' >> /etc/sysctl.d/99-kexec-load-disabled.conf",
          "condition": "no existing line found in any file"
        }
      ]
    }
  ]
}
